#include<bits/stdc++.h>
using namespace std;
long long root[100010];
struct segment_tree
{
    struct node
    {
        long long l,r,lson,rson;
        long long sum;
    }a[8000010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].sum=a[a[x].lson].sum+a[a[x].rson].sum;
    }
    void add(long long &x,long long p,long long v,long long newl,long long newr)
    {
        if(x==0)
        {
            x=++cnt;
            a[x].l=newl;
            a[x].r=newr;
            a[x].sum=0;
        }
        if(a[x].l==a[x].r)
        {
            a[x].sum+=v;
            return;
        }
        long long mid=(a[x].l+a[x].r)>>1;
        if(p<=mid)
        {
            add(a[x].lson,p,v,newl,mid);
        }
        else
        {
            add(a[x].rson,p,v,mid+1,newr);
        }
        pushup(x);
    }
    long long merge(long long ax,long long bx,long long l,long long r)
    {
        if(ax==0||bx==0)
        {
            return ax+bx;
        }
        if(l==r)
        {
            a[ax].sum+=a[bx].sum;
            return ax;
        }
        long long mid=(l+r)>>1;
        a[ax].lson=merge(a[ax].lson,a[bx].lson,l,mid);
        a[ax].rson=merge(a[ax].rson,a[bx].rson,mid+1,r);
        pushup(ax);
        return ax;
    }
    long long query(long long x,long long l,long long r,long long k)
    {
        if(k>a[x].sum)
        {
            return -1;
        }
        if(l==r)
        {
            return l;
        }
        long long mid=(l+r)>>1;
        long long p=a[a[x].lson].sum;
        if(k<=p)
        {
            return query(a[x].lson,l,mid,k);
        }
        else
        {
            return query(a[x].rson,mid+1,r,k-p);
        }
    }
}t;
long long fa[100010],pos[100010];
long long find(long long x)
{
    return (x==fa[x]?x:fa[x]=find(fa[x]));
}
long long n,m;
void merge(long long x,long long y)
{
    t.merge(root[find(x)],root[find(y)],1,n);
    fa[find(y)]=find(x);
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        fa[i]=i;
        long long x;
        scanf("%lld",&x);
        t.add(root[i],x,1,1,n);
        pos[x+1]=i;
    }
    for(long long i=1;i<=m;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        if(find(x)!=find(y))
        {
            merge(x,y);
        }
    }
    long long q;
    scanf("%lld",&q);
    pos[0]=-1;
    while(q--)
    {
        char op;
        long long x,y;
        cin>>op>>x>>y;
        if(op=='B')
        {
            if(find(x)!=find(y))
            {
                merge(x,y);
            }
        }
        else
        {
            printf("%lld\n",pos[t.query(root[find(x)],1,n,y)+1]);
        }
    }
    return 0;
}
